// Note: batches 1 (AL–GA), 3 (MA–NJ), and 4 (NM–SC) are populated as their agents return.
// Until then, unlisted states fall back to the template default in the state-subpage route.

export const STATE_OVERRIDES: Record<string, Record<string, StateOverride>> = {
  "offer-in-compromise-calculator": OIC_STATE_OVERRIDES,
};

/** Fetch the override for a specific spoke × state, if any. */
export function getStateOverride(spokeSlug: string, stateSlug: string): StateOverride | undefined {
  return STATE_OVERRIDES[spokeSlug]?.[stateSlug];
}
